from django.shortcuts import renderfrom .motor_calculo import *from decimal import Decimaldef moeda_para_decimal(valor):    if not valor:        return Decimal("0")    valor = valor.replace("R$", "")    valor = valor.replace(".", "")    valor = valor.replace(",", ".")    valor = valor.strip()    return Decimal(valor)def calculo(request):    resultado = None    tipo = None    aliquota = None    valor = Decimal("0")    if request.method == "POST":        valor = moeda_para_decimal(request.POST.get("valor_base"))        tipo = request.POST.get("tipo_ato")        aliquota = Decimal(request.POST.get("aliquota") or "0")        despesa = moeda_para_decimal(request.POST.get("despesa_extra"))        # ===============================        # VENDA E COMPRA        # ===============================        if tipo == "venda_compra":            resultado = venda_compra(valor, aliquota)            if despesa > 0:                resultado["despesa"] = despesa                resultado["total"] += despesa        # ===============================        # VENDA + CESSÃO        # ===============================        elif tipo == "venda_cessao":            valor_cessao = moeda_para_decimal(                request.POST.get("valor_cessao")            )            resultado = venda_cessao(                valor,                valor_cessao,                aliquota            )            if despesa > 0:                resultado["despesa"] = despesa                resultado["cessao"]["total"] += despesa        # ===============================        # ALIENAÇÃO FIDUCIÁRIA        # ===============================        elif tipo == "alienacao":            divida = moeda_para_decimal(                request.POST.get("valor_divida")            )            resultado = alienacao_fiduciaria(                valor,                divida,                aliquota            )            if despesa > 0:                resultado["despesa"] = despesa                resultado["venda"]["total"] += despesa        # ===============================        # VENDA COM USUFRUTO        # ===============================        elif tipo == "venda_usufruto":            resultado = venda_usufruto(                valor,                aliquota            )            if despesa > 0:                resultado["despesa"] = despesa                resultado["total"] += despesa        # ===============================        # DOAÇÃO / INVENTÁRIO        # ===============================        elif tipo == "doacao":            resultado = doacao_inventario(valor, aliquota)            if despesa > 0:                resultado["despesa"] = despesa                resultado["total"] += despesa        # ===============================        # DOAÇÃO COM USUFRUTO        # ===============================        elif tipo == "doacao_usufruto":            resultado = doacao_usufruto(valor, aliquota)            if despesa > 0:                resultado["despesa"] = despesa                resultado["total"] += despesa        # ===============================        # VENDA COM DESCONTO        # ===============================        elif tipo == "venda_desconto":            resultado = venda_desconto(                valor,                aliquota            )            if despesa > 0:                resultado["despesa"] = despesa                resultado["total"] += despesa    return render(        request,        "calculo.html",        {            "resultado": resultado,            "tipo_ato": tipo,            "aliquota": aliquota,            "valor_base": valor        }    )